-- ----------------------------
-- Table structure for barrage_messages
-- ----------------------------
DROP TABLE IF EXISTS `barrage_messages`;
CREATE TABLE `barrage_messages`  (
  `id` bigint(0) NOT NULL AUTO_INCREMENT,
  `alert_level` enum('ATTENTION','CRITICAL','NORMAL','WARNING') CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL,
  `alpha_value` double NOT NULL,
  `beta_value` double NOT NULL,
  `confidence_score` double NULL DEFAULT NULL,
  `content` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL,
  `created_at` datetime(6) NOT NULL,
  `data_end_time` datetime(6) NOT NULL,
  `data_start_time` datetime(6) NOT NULL,
  `delta_value` double NOT NULL,
  `dominant_frequency` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL,
  `gamma_value` double NOT NULL,
  `primary_state` enum('ALERT','CREATIVE','DEEP_RELAXATION','DROWSY','FOCUSED','HYPERACTIVE','MEDITATIVE','RELAXED','STRESSED','UNBALANCED') CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL,
  `recommendation` varchar(200) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL,
  `sample_count` int(0) NOT NULL,
  `theta_value` double NOT NULL,
  `user_id` bigint(0) NOT NULL,
  PRIMARY KEY (`id`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 17 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_0900_ai_ci ROW_FORMAT = Dynamic;

-- ----------------------------
-- Records of barrage_messages
-- ----------------------------

-- ----------------------------
-- Table structure for conversation_history
-- ----------------------------
DROP TABLE IF EXISTS `conversation_history`;
CREATE TABLE `conversation_history`  (
  `id` bigint(0) NOT NULL AUTO_INCREMENT,
  `ai_response` longtext CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL,
  `conversation_session_id` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL,
  `conversation_timestamp` datetime(6) NOT NULL,
  `created_at` datetime(6) NOT NULL,
  `eeg_session_id` bigint(0) NULL DEFAULT NULL,
  `is_bookmarked` bit(1) NULL DEFAULT NULL,
  `notes` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL,
  `processing_duration_ms` bigint(0) NULL DEFAULT NULL,
  `query_category` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL,
  `response_tokens` json NULL,
  `session_title` varchar(200) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL,
  `tools_used` json NULL,
  `updated_at` datetime(6) NOT NULL,
  `used_mcp_tools` bit(1) NULL DEFAULT NULL,
  `user_id` bigint(0) NOT NULL,
  `user_query` text CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL,
  `user_rating` int(0) NULL DEFAULT NULL,
  PRIMARY KEY (`id`) USING BTREE,
  INDEX `idx_user_session`(`user_id`, `conversation_session_id`, `created_at`) USING BTREE,
  INDEX `idx_user_created`(`user_id`, `created_at`) USING BTREE,
  INDEX `idx_session_created`(`conversation_session_id`, `created_at`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 74 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_0900_ai_ci ROW_FORMAT = Dynamic;

