INSERT INTO `conversation_history` VALUES (36, '基于你最近的EEG会话（会话ID 13，时间范围：2025-08-30T09:15:12.997174 - 2025-08-30T09:28:13.023419，持续13分钟），我为你生成了完整的EEG数据摘要。以下是详细的分析结果：\n\n### 会话信息\n- **采样率**：~250Hz\n- **通道数**：8\n- **数据流**：原始时间序列 (TimeSeriesRaw)、滤波时间序列 (TimeSeriesFilt)、平均频段功率 (AvgBandPower)\n- **数据来源**：OpenBCI GUI v6.0.0_beta1\n\n### 基本统计\n- **总通道数**：8\n- **数据类型**：EEG\n- **采样信息**：~250Hz, 8通道\n- **数据质量**：良好\n- **通道统计**：\n  - 滤波数据通道：8\n  - 原始数据可用：是\n  - 滤波数据可用：是\n  - 原始数据通道：8\n\n### 频域特征\n- **频率频段**：Alpha (8-13Hz), Beta (13-30Hz), Delta (0.5-4Hz), Gamma (30-100Hz), Theta (4-8Hz)\n- **主导频率**：需要进一步分析\n- **功率分布**：优化分析\n- **频段功率统计**：\n  - 优化应用：是\n  - 频段数量：5\n  - 可用频段：Alpha, Beta, Delta, Gamma, Theta\n  - 数据策略：AGGRESSIVE_SAMPLING\n\n### 时域模式\n- **模式类型**：优化的时间序列分析\n- **稳定性指数**：0.75\n- **变化点**：无显著变化点\n- **时域特征**：\n  - 时域分析可用：是\n  - 优化策略：AGGRESSIVE_SAMPLING\n  - 分析时间窗口：8\n  - 聚合应用：是\n\n### 数据质量\n- **总体质量**：良好\n- **数据完整性**：95.0%\n- **信号质量**：85.0%\n- **伪迹水平**：低\n- **质量指标**：\n  - 通道完整性：1.0\n  - 独特通道数：8\n  - 总样本数：1,546,000\n\n### 空间特征\n- **通道相关性**：\n  - 分析类型：优化的空间分析\n  - 策略：AGGRESSIVE_SAMPLING\n- **脑区**：前额 (Frontal), 中央 (Central), 顶叶 (Parietal), 枕叶 (Occipital)\n- **空间模式**：优化分析\n- **区域分析**：\n  - 区域数量：4\n  - 优化应用：是\n  - 分析区域：中央 (Central), 前额 (Frontal), 枕叶 (Occipital), 顶叶 (Parietal)\n\n### 优化处理\n- **大数据量优化**：采用分层采样和聚合算法\n\n### 分析元数据\n- **兼容模式**：大数据优化\n- **优化策略**：AGGRESSIVE_SAMPLING\n- **分析版本**：1.1-optimized\n- **InfluxDB版本**：3.2.1\n- **配置**：\n  - 分析级别：全面\n  - 时域窗口大小：2.0秒\n  - 目标特征：时域模式、频域特征、空间相关性、质量指标\n  - 包含伪迹检测：是\n  - 包含空间分析：是\n  - 自定义参数：无\n\n### 重要说明\n- 由于数据量较大，采用了优化策略进行分层采样和聚合，以确保高效处理。\n- 主导频率和具体频段功率分布需要进一步详细分析。\n\n这个综合报告提供了你认知负荷研究所需的时域、频域和空间特征的初步分析。如果你需要更详细的某个方面的分析，请告诉我。', 'user_1_1756546671840', '2025-08-30 09:39:39.704197', '2025-08-30 17:39:39.705193', NULL, b'0', NULL, 107861, 'DATA_QUERY', '{\"total_tokens\": 19232, \"prompt_tokens\": 18287, \"completion_tokens\": 945, \"collaborationStats\": {\"toolCount\": 0, \"collaborationType\": \"no_tools_used\", \"qualityAssessment\": \"no_tools\", \"collaborationEfficiency\": 0.0}, \"prompt_tokens_details\": {\"cached_tokens\": 0}, \"mcpToolsIntegrationSuccess\": true, \"toolCollaborationEfficiency\": 0.0}', '为我的认知负荷研究生成完整的EEG数据摘要，包括时域、...', NULL, '2025-08-30 17:39:39.705193', b'0', 1, '为我的认知负荷研究生成完整的EEG数据摘要，包括时域、频域和空间特征分析。', NULL);
