INSERT INTO `conversation_history` VALUES (72, '根据您的请求，我查询了会话ID 17（2025-10-17 08:20:56.140 - 08:21:44.664）的最新10个时间点的频谱数据。以下是详细的分析结果：\n\n### 数据来源和计算方法\n- **时间范围**：2025-10-17 08:20:56.140 - 08:21:44.664\n- **记录数量**：每个时间点包含5个频段（Alpha, Delta, Theta, Beta, Gamma），共10个时间点。\n- **计算方法**：基于Welch功率谱密度估计方法。\n\n### 频谱数据分析\n以下是每个时间点的频段功率值（单位：μV²）：\n\n| 时间点 | Alpha | Delta | Theta | Beta | Gamma |\n|--------|-------|-------|-------|------|-------|\n| 08:21:43.975 | 0.020114103 | 2.0823954E-4 | 0.018080374 | 0.28742716 | 0.6741701 |\n| 08:21:43.960 | 0.02026225 | 2.0818808E-4 | 0.017876893 | 0.28702217 | 0.6746305 |\n| 08:21:43.945 | 0.020401184 | 2.0771945E-4 | 0.01767597 | 0.286789 | 0.67492604 |\n| 08:21:43.929 | 0.020533338 | 2.0642739E-4 | 0.01747824 | 0.28652102 | 0.67526096 |\n| 08:21:43.913 | 0.02065794 | 2.0552811E-4 | 0.017294444 | 0.28632742 | 0.6755147 |\n| 08:21:43.898 | 0.020787695 | 2.0433156E-4 | 0.017116677 | 0.28616244 | 0.67572886 |\n| 08:21:43.883 | 0.020906499 | 2.0377235E-4 | 0.016946264 | 0.2860099 | 0.67593354 |\n| 08:21:43.868 | 0.02102171 | 2.0292436E-4 | 0.016788756 | 0.28589606 | 0.67609054 |\n| 08:21:43.850 | 0.021126952 | 2.0245419E-4 | 0.016646331 | 0.2858134 | 0.6762108 |\n| 08:21:43.834 | 0.021216031 | 2.0114295E-4 | 0.016510144 | 0.28577295 | 0.67629975 |\n\n### 统计分析\n- **Alpha频段**：\n  - 平均功率：0.021207899 μV²\n  - 中位数功率：0.021427684 μV²\n  - 标准差：4.858304640875321E-4 μV²\n  - 四分位距 (IQR)：7.022020000000025E-4 μV²\n\n- **Delta频段**：\n  - 平均功率：1.989925524E-4 μV²\n  - 中位数功率：1.9860062E-4 μV²\n  - 标准差：5.816683623478589E-6 μV²\n  - 四分位距 (IQR)：1.0202239999999998E-5 μV²\n\n- **Theta频段**：\n  - 平均功率：0.01649494632 μV²\n  - 中位数功率：0.016199175 μV²\n  - 标准差：7.150461153986688E-4 μV²\n  - 四分位距 (IQR)：0.0010296049999999994 μV²\n\n- **Beta频段**：\n  - 平均功率：0.2862984328 μV²\n  - 中位数功率：0.28626645 μV²\n  - 标准差：4.3983817530352843E-4 μV²\n  - 四分位距 (IQR)：7.007399999999775E-4 μV²\n\n- **Gamma频段**：\n  - 平均功率：0.6757997196 μV²\n  - 中位数功率：0.67593354 μV²\n  - 标准差：5.639730534452248E-4 μV²\n  - 四分位距 (IQR)：6.196499999999716E-4 μV²\n\n### 神经科学解释\n- **Alpha频段 (8-13Hz)**：闭眼清醒状态、放松警觉、视觉皮层同步。典型振幅为20-100 μV²。\n- **Delta频段 (1-4Hz)**：深度睡眠、无意识状态、皮层抑制。典型振幅为50-200 μV²。\n- **Theta频段 (4-8Hz)**：REM睡眠、冥想状态、记忆巩固、创造性思维。典型振幅为10-50 μV²。\n- **Beta频段 (13-30Hz)**：主动思维、注意力集中、运动皮层激活。典型振幅为5-30 μV²。\n- **Gamma频段 (30-100Hz)**：意识绑定、高级认知功能、跨区域神经同步。典型振幅为1-10 μV²。\n\n### 信号质量评估\n所有频段的数据完整性比率为1.0，表明数据完整且没有缺失。\n\n如果您需要更详细的某个方面分析或进一步的解释，请告诉我！', 'user_1_1760689300997', '2025-10-17 08:23:16.804188', '2025-10-17 16:23:16.833543', 17, b'0', NULL, 95791, 'DATA_QUERY', '{\"total_tokens\": 11799, \"prompt_tokens\": 9958, \"completion_tokens\": 1841, \"collaborationStats\": {\"toolCount\": 0, \"collaborationType\": \"no_tools_used\", \"qualityAssessment\": \"no_tools\", \"collaborationEfficiency\": 0.0}, \"prompt_tokens_details\": {\"cached_tokens\": 0}, \"mcpToolsIntegrationSuccess\": true, \"toolCollaborationEfficiency\": 0.0}', '我想查看最新的十条频谱数据', NULL, '2025-10-17 16:23:16.833543', b'0', 1, '我想查看最新的十条频谱数据', NULL);
INSERT INTO `conversation_history` VALUES (73, '根据您当前的EEG会话（会话ID 17，2025-10-17 08:20:56.140 - 至今），我分析了最新的10个时间点的频谱数据（时间范围：2025-10-17T08:24:41.840 - 2025-10-17T08:24:41.980）。以下是基于这些数据的频段功率统计分析：\n\n- **Alpha频段 (8-13Hz)**:\n  - 平均功率: 0.020565 μV²\n  - 中位数功率: 0.020695 μV²\n  - 标准差: 0.000613 μV²\n  - 四分位距 (IQR): 0.00103 μV²\n  - 生物学意义: 放松警觉，默认模式网络，闭眼清醒状态\n\n- **Beta频段 (13-30Hz)**:\n  - 平均功率: 0.286036 μV²\n  - 中位数功率: 0.287029 μV²\n  - 标准差: 0.003828 μV²\n  - 四分位距 (IQR): 0.006623 μV²\n  - 生物学意义: 专注状态，执行控制，主动思维\n\n- **Delta频段 (1-4Hz)**:\n  - 平均功率: 0.000193 μV²\n  - 中位数功率: 0.000191 μV²\n  - 标准差: 0.000006 μV²\n  - 四分位距 (IQR): 0.000011 μV²\n  - 生物学意义: 深度睡眠，异常时可能提示脑损伤\n\n- **Theta频段 (4-8Hz)**:\n  - 平均功率: 0.013400 μV²\n  - 中位数功率: 0.013452 μV²\n  - 标准差: 0.000270 μV²\n  - 四分位距 (IQR): 0.000507 μV²\n  - 生物学意义: 工作记忆，创造性任务，REM睡眠\n\n- **Gamma频段 (30-100Hz)**:\n  - 平均功率: 0.679805 μV²\n  - 中位数功率: 0.678438 μV²\n  - 标准差: 0.004325 μV²\n  - 四分位距 (IQR): 0.007176 μV²\n  - 生物学意义: 意识统一，特征绑定，高级认知功能\n\n从这些数据来看，您的Alpha频段功率相对较低，而Beta频段功率较高。这可能表明您目前处于一种较为专注和主动思考的状态。同时，Gamma频段功率也较高，这可能与高级认知功能有关。\n\n请注意，这些结果是基于最近的数据点进行的统计分析，并且需要结合更多的上下文信息来做出更准确的判断。如果您有更多具体的问题或需要进一步的详细分析，请告诉我！', 'user_1_1760689300997', '2025-10-17 08:25:20.556034', '2025-10-17 16:25:20.580951', 17, b'0', NULL, 57286, 'TECHNICAL_SUPPORT', '{\"total_tokens\": 11125, \"prompt_tokens\": 10327, \"completion_tokens\": 798, \"collaborationStats\": {\"toolCount\": 0, \"collaborationType\": \"no_tools_used\", \"qualityAssessment\": \"no_tools\", \"collaborationEfficiency\": 0.0}, \"prompt_tokens_details\": {\"cached_tokens\": 0}, \"mcpToolsIntegrationSuccess\": true, \"toolCollaborationEfficiency\": 0.0}', NULL, NULL, '2025-10-17 16:25:20.580951', b'0', 1, '我现在的精神状态怎么样', NULL);

-- ----------------------------
-- Table structure for eeg_sessions
-- ----------------------------
DROP TABLE IF EXISTS `eeg_sessions`;
CREATE TABLE `eeg_sessions`  (
  `id` bigint(0) NOT NULL AUTO_INCREMENT,
  `band_port` int(0) NULL DEFAULT NULL,
  `band_stream_end_time_utc` datetime(6) NULL DEFAULT NULL,
  `band_stream_last_packet_time_utc` datetime(6) NULL DEFAULT NULL,
  `band_stream_start_time_utc` datetime(6) NULL DEFAULT NULL,
  `band_stream_status` enum('ACTIVE','COMPLETED','ERROR','PAUSED','WAITING') CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL,
  `band_stream_total_packets` bigint(0) NULL DEFAULT 0,
  `created_at` datetime(6) NULL DEFAULT NULL,
  `filt_port` int(0) NULL DEFAULT NULL,
  `filt_stream_end_time_utc` datetime(6) NULL DEFAULT NULL,
  `filt_stream_last_packet_time_utc` datetime(6) NULL DEFAULT NULL,
  `filt_stream_start_time_utc` datetime(6) NULL DEFAULT NULL,
  `filt_stream_status` enum('ACTIVE','COMPLETED','ERROR','PAUSED','WAITING') CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL,
  `filt_stream_total_packets` bigint(0) NULL DEFAULT 0,
  `notes` varchar(1000) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL,
  `raw_port` int(0) NULL DEFAULT NULL,
  `raw_stream_end_time_utc` datetime(6) NULL DEFAULT NULL,
  `raw_stream_last_packet_time_utc` datetime(6) NULL DEFAULT NULL,
  `raw_stream_start_time_utc` datetime(6) NULL DEFAULT NULL,
  `raw_stream_status` enum('ACTIVE','COMPLETED','ERROR','PAUSED','WAITING') CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL,
  `raw_stream_total_packets` bigint(0) NULL DEFAULT 0,
  `session_end_time` datetime(6) NULL DEFAULT NULL,
  `session_end_time_utc` datetime(6) NULL DEFAULT NULL,
  `session_start_time` datetime(6) NOT NULL,
  `session_start_time_utc` datetime(6) NOT NULL,
  `session_status` enum('ACTIVE','COMPLETED','ERROR','INTERRUPTED') CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL,
  `total_duration_seconds` bigint(0) NULL DEFAULT NULL,
  `updated_at` datetime(6) NULL DEFAULT NULL,
  `user_id` bigint(0) NOT NULL,
  `user_timezone` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL,
  PRIMARY KEY (`id`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 18 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_0900_ai_ci ROW_FORMAT = Dynamic;

